begin;select plan(20);
select has_table('public','qapi_projects','QAPI projects exist');
select has_table('public','qapi_measurements','QAPI measurements are structured');
select has_table('public','qapi_meeting_notes','QAPI meeting notes exist');
select ok(not has_table_privilege('authenticated','public.qapi_measurements','UPDATE'),'measurements cannot be rewritten by browser roles');
insert into public.organizations(id,name,slug,subscription_status)values('60000000-0000-4000-8000-000000000001','QAPI Org','qapi-org','active');
insert into public.facilities(id,organization_id,name,facility_type)values('60000000-0000-4000-8000-000000000011','60000000-0000-4000-8000-000000000001','QAPI Facility','PCH');
insert into auth.users(instance_id,id,aud,role,email,encrypted_password,email_confirmed_at,raw_app_meta_data,raw_user_meta_data,created_at,updated_at,confirmation_token,recovery_token,email_change_token_new,email_change,email_change_token_current,reauthentication_token,is_sso_user,is_anonymous)values('00000000-0000-0000-0000-000000000000','60000000-0000-4000-8000-000000000101','authenticated','authenticated','qapi@test.local','x',now(),'{}','{}',now(),now(),'','','','','','',false,false);
select set_config('app.privileged_write','on',true);insert into public.profiles(id,organization_id,email,first_name,last_name,role,is_active)values('60000000-0000-4000-8000-000000000101','60000000-0000-4000-8000-000000000001','qapi@test.local','QAPI','Lead','org_admin',true)on conflict(id)do update set organization_id=excluded.organization_id,role=excluded.role,is_active=true;select set_config('app.privileged_write','off',true);
insert into public.residents(id,organization_id,facility_id,first_name,last_name,admission_date)values('60000000-0000-4000-8000-000000000201','60000000-0000-4000-8000-000000000001','60000000-0000-4000-8000-000000000011','Quality','Resident',current_date);
insert into public.resident_change_events(id,organization_id,facility_id,resident_id,category,identified_at,immediate_observations,immediate_action_taken,follow_up_due_at,incident_decision)values('60000000-0000-4000-8000-000000000301','60000000-0000-4000-8000-000000000001','60000000-0000-4000-8000-000000000011','60000000-0000-4000-8000-000000000201','fall',now(),'Observed fall','Safety response',now()+interval'1 hour','not_required');
create or replace function pg_temp.act_as(p_id uuid,p_role text default'authenticated')returns void language plpgsql as $$begin reset role;perform set_config('request.jwt.claims',jsonb_build_object('sub',p_id,'role',p_role,'aal','aal1','iat',extract(epoch from now())::bigint)::text,true);if p_role='service_role'then set local role service_role;else set local role authenticated;end if;end$$;
create temporary table qids(key text primary key,id uuid)on commit drop;grant all on qids to authenticated,service_role;
select pg_temp.act_as('60000000-0000-4000-8000-000000000101');
select is((public.get_qapi_source_metrics('60000000-0000-4000-8000-000000000011',current_date-1,current_date)->>'falls')::integer,1,'source metrics count falls');
insert into qids values('project',public.create_qapi_project('60000000-0000-4000-8000-000000000011','Reduce resident falls','Falls increased above the facility baseline.','Fall trend','3 falls in prior month','Reduce falls through environmental and service interventions.','No more than 1 fall monthly',1,current_date+90,'60000000-0000-4000-8000-000000000101','resident_change_event','60000000-0000-4000-8000-000000000301'));
select is((select status from public.qapi_projects where id=(select id from qids where key='project')),'proposed','new project is proposed');
select is(public.create_qapi_project('60000000-0000-4000-8000-000000000011','Duplicate','Duplicate signal should not create another project.','Fall trend','','','','1',current_date+90,'60000000-0000-4000-8000-000000000101','resident_change_event','60000000-0000-4000-8000-000000000301'),(select id from qids where key='project'),'signal ingestion is idempotent');
select lives_ok($$select public.add_qapi_action((select id from qids where key='project'),'Complete environmental rounds','Inspect resident areas and remove hazards.','systemic','60000000-0000-4000-8000-000000000101',now()+interval'14 days')$$,'project creates owned action');
select is((select count(*)::integer from public.qapi_action_items where project_id=(select id from qids where key='project')),1,'action links to work engine');
select lives_ok($$select public.record_qapi_measurement((select id from qids where key='project'),current_date-30,current_date,3,40,'Baseline fall rate','40 resident-month sample')$$,'baseline measurement recorded');
select is((select result_value from public.qapi_measurements where project_id=(select id from qids where key='project')),7.50::numeric,'measurement computes percent');
select lives_ok($$select public.add_qapi_meeting_note((select id from qids where key='project'),now(),'Administrator, care team, quality lead','Reviewed baseline and interventions.','Night lighting inconsistency','Add lighting audit to rounds')$$,'meeting note recorded');
select lives_ok($$select public.update_qapi_project_plan((select id from qids where key='project'),'active','[{"name":"QAPI Lead"}]','five_whys','Environmental hazards and inconsistent rounding contributed to falls.','Environmental rounds, lighting audit, and staff reinforcement.','monthly','40 resident-months','','','','','Project activated after QAPI review')$$,'project activates with RCA and interventions');
select throws_ok($$select public.update_qapi_project_plan((select id from qids where key='project'),'closed','[]','five_whys','Environmental hazards and inconsistent rounding contributed to falls.','Plan','monthly','40','','','Effective','90 days','Close now')$$,'55000',null,'project cannot skip pending closure');
select lives_ok($$select public.update_qapi_project_plan((select id from qids where key='project'),'pending_closure','[]','five_whys','Environmental hazards and inconsistent rounding contributed to falls.','Plan','monthly','40','','','Fall target sustained','90 days','Submit for final closure review')$$,'evidence-backed project reaches closure review');
select lives_ok($$select public.update_qapi_project_plan((select id from qids where key='project'),'closed','[]','five_whys','Environmental hazards and inconsistent rounding contributed to falls.','Plan','monthly','40','','','Fall target sustained','90 days','Final QAPI closure approved')$$,'final closure is approved');
select is((select status from public.qapi_projects where id=(select id from qids where key='project')),'closed','project closes');
select ok((select final_closure_approved_at is not null from public.qapi_projects where id=(select id from qids where key='project')),'closure approval is attributable');
reset role;
select throws_ok($$delete from public.qapi_measurements where project_id=(select id from qids where key='project')$$,'55000',null,'measurements are immutable');
select is((select count(*)::integer from public.qapi_project_history where project_id=(select id from qids where key='project')),5,'project history retains lifecycle');
select * from finish();rollback;
